SELECT COUNT(event_id) AS event_count
FROM venture_events
WHERE venture_id = 1;

SELECT event_name
FROM venture_events
WHERE location = 'New York';

SELECT venture_id, description
FROM entrepreneurial_ventures
WHERE venture_date > '2010-01-01';

SELECT SUM(amount) AS total_funding
FROM funding
WHERE company_id = 0;

SELECT COUNT(publication_id) AS publication_count
FROM research_publications
WHERE venture_id = 1;

SELECT venture_id, MIN(metric_value) AS min_metric_value
FROM venture_metrics
WHERE venture_id = 0;

SELECT category_id, sub_category
FROM venture_categories
WHERE venture_id = 1;

SELECT COUNT(venture_id) AS venture_count
FROM entrepreneurial_ventures
WHERE founder_id = 1;

SELECT name
FROM companies
WHERE company_id IN (
  SELECT company_id
  FROM funding
);

SELECT venture_id, investor_id, investment_date
FROM venture_investors
WHERE investment_date = '2020-01-01';
